import { createStreamableUI } from 'ai/rsc';
import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { readFileSync } from 'fs';

export async function CodeAssistant({ repoPath, query }: { repoPath: string; query: string }) {
  const files = ['package.json', 'src/index.ts'].map(f => 
    readFileSync(`${repoPath}/${f}`, 'utf-8')
  );

  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: `Repo files: ${files.join('\n')}\nUser: ${query}`,
  });

  const ui = createStreamableUI();
  ui.update(result.textStream);
  return ui.value;
}

