import { createVexClient } from '@vex_dev/sdk/server';

const vex = createVexClient({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'coding-assistant',
});

export async function safeGenerateText(params: GenerateTextParams) {
  const rawResult = await generateText(params);

  const verification = await vex.verify({
    input: params.prompt,
    output: rawResult.text,
    checks: [
      'code_correctness',
      'security_vulnerabilities',
      'no_credential_leakage',
      'dependency_safety',
      'license_compliance',
    ],
  });

  if (!verification.passed) {
    throw new Error(`Verification failed: ${verification.issues.join(', ')}`);
  }

  return rawResult;
}

import { createStreamableValue } from 'ai/rsc';

export async function safeStreamText(params: StreamTextParams) {
  const stream = await streamText(params);
  const ui = createStreamableValue('');

  let buffer = '';

  for await (const chunk of stream.textStream) {
    buffer += chunk;

    // Verify complete code blocks
    if (buffer.includes('```') && buffer.includes('```', buffer.lastIndexOf('```'))) {
      const verification = await vex.verify({
        input: params.messages,
        output: buffer,
        checks: ['code_correctness'],
      });

      if (verification.passed) {
        ui.update(buffer);
      }
      buffer = '';
    }
  }

  return ui.value;
}

const safeTools = {
  executeCode: {
    ...tools.executeCode,
    execute: async (params) => {
      const rawResult = await tools.executeCode.execute(params);

      const verification = await vex.verify({
        input: params.code,
        output: rawResult.output,
        checks: [
          'no_credential_leakage',
          'security_vulnerabilities',
          'dependency_safety',
        ],
      });

      if (!verification.passed) {
        return { error: 'Code failed safety checks', issues: verification.issues };
      }

      return rawResult;
    },
  },
};
